947   // (X+1) <u X        --> X >u (MAXUINT-1)        --> X == 255
948   // (X+2) <u X        --> X >u (MAXUINT-2)        --> X > 253
949   // (X+MAXUINT) <u X  --> X >u (MAXUINT-MAXUINT)  --> X != 0
