198 Value *InstCombinerImpl::EmitGEPOffset(GEPOperator *GEP, bool RewriteGEP) {
199   if (!RewriteGEP)
200     return llvm::emitGEPOffset(&Builder, DL, GEP);
201 
202   IRBuilderBase::InsertPointGuard Guard(Builder);
203   auto *Inst = dyn_cast<Instruction>(GEP);
204   if (Inst)
205     Builder.SetInsertPoint(Inst);
206 
207   Value *Offset = EmitGEPOffset(GEP);
208   // If a non-trivial GEP has other uses, rewrite it to avoid duplicating
209   // the offset arithmetic.
210   if (Inst && !GEP->hasOneUse() && !GEP->hasAllConstantIndices() &&
211       !GEP->getSourceElementType()->isIntegerTy(8)) {
212     replaceInstUsesWith(
213         *Inst, Builder.CreateGEP(Builder.getInt8Ty(), GEP->getPointerOperand(),
214                                  Offset, "", GEP->getNoWrapFlags()));
215     eraseInstFromFunction(*Inst);
216   }
217   return Offset;
218 }
