414 Value *InstCombinerImpl::simplifyIntToPtrRoundTripCast(Value *Val) {
415   auto *IntToPtr = dyn_cast<IntToPtrInst>(Val);
416   if (IntToPtr && DL.getTypeSizeInBits(IntToPtr->getDestTy()) ==
417                       DL.getTypeSizeInBits(IntToPtr->getSrcTy())) {
418     auto *PtrToInt = dyn_cast<PtrToIntInst>(IntToPtr->getOperand(0));
419     Type *CastTy = IntToPtr->getDestTy();
420     if (PtrToInt &&
421         CastTy->getPointerAddressSpace() ==
422             PtrToInt->getSrcTy()->getPointerAddressSpace() &&
423         DL.getTypeSizeInBits(PtrToInt->getSrcTy()) ==
424             DL.getTypeSizeInBits(PtrToInt->getDestTy()))
425       return PtrToInt->getOperand(0);
426   }
427   return nullptr;
428 }
